// encode_audio.c - ترميز samples صوتية خامة إلى حزم مضغوطة
#include <libavcodec/avcodec.h>
#include <libavutil/frame_alloc.h>
#include <libavutil/opt.h>
#include <stdio.h>

int main(void) {
    const AVCodec *codec = avcodec_find_encoder(AV_CODEC_ID_AAC);
    if (!codec) {
        fprintf(stderr, "AAC encoder غير متوفر\n");
        return 1;
    }

    AVCodecContext *ctx = avcodec_alloc_context3(codec);
    ctx->sample_rate = 44100;
    ctx->ch_layout = AV_CH_LAYOUT_STEREO;
    ctx->sample_fmt = AV_SAMPLE_FMT_FLTP;
    ctx->bit_rate = 128000;
    avcodec_open2(ctx, codec, NULL);

    // إنشاء frame فارغ
    AVFrame *frame = av_frame_alloc();
    frame->nb_samples = ctx->frame_size;
    frame->format = ctx->sample_fmt;
    frame->ch_layout = ctx->ch_layout;
n    av_frame_get_buffer(frame, 0);

    // ملء الـ frame بعينات صوتية خامة
    float *samples = (float *)frame->data[0];
    for (int i = 0; i < frame->nb_samples * 2; i++) {
        samples[i] = 0.5f * sinf(2.0f * 3.14159f * i / (frame->nb_samples * 2));
    }

    // ترميز
    AVPacket *pkt = av_packet_alloc();
    frame->pts = 0;
    int pts_step = frame->nb_samples;

    for (int i = 0; i < 100; i++) {
        frame->pts = i * pts_step;
        int ret = avcodec_send_frame(ctx, frame);
        while (ret >= 0) {
            ret = avcodec_receive_packet(ctx, pkt);
            if (ret == AVERROR(EAGAIN) || ret == AVERROR_EOF) break;
n            printf("encoded: packet size=%d pts=%ld\n", pkt->size, pkt->pts);
            av_packet_unref(pkt);
        }
    }

    av_packet_free(&pkt);
    av_frame_free(&frame);
    avcodec_free_context(&ctx);
    return 0;
}

